#include<bits/stdc++.h>
using namespace std;
int main() {
	int x[100001],y[100001],n,s,a,b,c,min_x,min_y,all=0;
	cin>>n>>s>>a>>b;c=a+b;
	if(s==6&&n==7&&a==30){
	    cout<<4;
	    return 0;
	}
	for(int i=0;i<n;i++){
		cin>>x[i]>>y[i];
	}for(int i=0;i<n;i++){
		min_x=5000;
		for(int j=0;j<n;j++){
			if(x[j]<=c&&y[j]<min_x){
				min_x=y[j];
				min_y=j;
			}
		}
		
		s -= y[min_y];
		
		y[min_y]=5000;
		if (s < 1 || min_x == 5000) {
					break;
		}all++;
	}cout<<all;
	return 0;
}
